const revealBtn = document.getElementById("revealBtn");
const loveMessageSection = document.getElementById("loveMessage");
const typedMessage = document.getElementById("typedMessage");
const daysCount = document.getElementById("daysCount");
const surpriseBtn = document.getElementById("surpriseBtn");
const surpriseMessage = document.getElementById("surpriseMessage");
const musicToggle = document.getElementById("musicToggle");
const bgMusic = document.getElementById("bgMusic");
const heartContainer = document.getElementById("heartContainer");
const sparkleContainer = document.getElementById("sparkleContainer");

const loveDate = new Date("2021-08-02T00:00:00");
const romanticMessage = `My love,

Every day with you feels like a soft sunrise after a long night.
You make my world calmer, brighter, and warmer in ways words can barely hold.

Thank you for your laughter, your kindness, and the way you love me so purely.
With you, even the smallest moments become precious memories.

I love your smile, your heart, your dreams, and everything that makes you... you.
No matter where life takes us, my heart will always find its way back to yours.

Forever yours. `;

let typingStarted = false;
let isMusicPlaying = false;

function updateLoveCounter() {
  const now = new Date();
  const diff = now - loveDate;
  const days = Math.max(0, Math.floor(diff / (1000 * 60 * 60 * 24)));
  daysCount.textContent = days.toLocaleString();
}

function typeWriter(text, element, speed = 30) {
  element.textContent = "";
  let i = 0;

  const intervalId = setInterval(() => {
    element.textContent += text.charAt(i);
    i += 1;

    if (i >= text.length) {
      clearInterval(intervalId);
    }
  }, speed);
}

function revealLoveMessage() {
  loveMessageSection.classList.remove("hidden");
  if (!typingStarted) {
    typingStarted = true;
    typeWriter(romanticMessage, typedMessage, 26);
  }

  loveMessageSection.scrollIntoView({
    behavior: "smooth",
    block: "start"
  });
}

function toggleSurprise() {
  surpriseMessage.classList.toggle("hidden");
  if (surpriseMessage.classList.contains("hidden")) {
    surpriseBtn.textContent = "Don't click this ";
  } else {
    surpriseBtn.textContent = "You clicked it ";
  }
}

async function toggleMusic() {
  try {
    if (isMusicPlaying) {
      bgMusic.pause();
      isMusicPlaying = false;
      musicToggle.textContent = " Music: Off";
      return;
    }

    await bgMusic.play();
    isMusicPlaying = true;
    musicToggle.textContent = " Music: On";
  } catch (error) {
    isMusicPlaying = false;
    musicToggle.textContent = " Tap to Play";
  }
}

function spawnHeart() {
  const heart = document.createElement("span");
  heart.className = "heart";
  heart.textContent = Math.random() > 0.35 ? "" : "";

  const left = Math.random() * 100;
  const duration = 7000 + Math.random() * 5000;
  const size = 12 + Math.random() * 24;

  heart.style.left = `${left}vw`;
  heart.style.bottom = "-40px";
  heart.style.fontSize = `${size}px`;
  heart.style.animationDuration = `${duration}ms`;

  heartContainer.appendChild(heart);

  setTimeout(() => heart.remove(), duration);
}

function spawnSparkle() {
  const sparkle = document.createElement("span");
  sparkle.className = "sparkle";

  const left = Math.random() * 100;
  const top = Math.random() * 100;
  const duration = 2500 + Math.random() * 2400;

  sparkle.style.left = `${left}vw`;
  sparkle.style.top = `${top}vh`;
  sparkle.style.animationDuration = `${duration}ms`;

  sparkleContainer.appendChild(sparkle);

  setTimeout(() => sparkle.remove(), duration);
}

function initParticles() {
  setInterval(spawnHeart, 520);
  setInterval(spawnSparkle, 360);
}

function initEvents() {
  revealBtn.addEventListener("click", revealLoveMessage);
  surpriseBtn.addEventListener("click", toggleSurprise);
  musicToggle.addEventListener("click", toggleMusic);
}

function init() {
  updateLoveCounter();
  initEvents();
  initParticles();
}

init();

const revealBtn = document.getElementById("revealBtn");
const loveMessageSection = document.getElementById("loveMessage");
const typedMessage = document.getElementById("typedMessage");
const daysCount = document.getElementById("daysCount");
const surpriseBtn = document.getElementById("surpriseBtn");
const surpriseMessage = document.getElementById("surpriseMessage");
const musicToggle = document.getElementById("musicToggle");
const bgMusic = document.getElementById("bgMusic");
const heartContainer = document.getElementById("heartContainer");
const sparkleContainer = document.getElementById("sparkleContainer");

const loveDate = new Date("2021-08-02T00:00:00");
const romanticMessage = `My love Romaliza,

Every day with you feels like a soft sunrise after a long night.
You make my world calmer, brighter, and warmer in ways words can barely hold.

Thank you for your laughter, your kindness, and the way you love me so purely.
With you, even the smallest moments become precious memories.

I love your smile, your heart, your dreams, and everything that makes you... you.
No matter where life takes us, my heart will always find its way back to yours.

Forever yours. `;

let typingStarted = false;
let isMusicPlaying = false;
let sectionObserver = null;
let motionProfile = null;

function getMotionProfile() {
  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const isSmallMobile = window.matchMedia("(max-width: 480px)").matches;
  const isTablet = window.matchMedia("(max-width: 768px)").matches;
  const isCoarsePointer = window.matchMedia("(pointer: coarse)").matches;

  if (prefersReducedMotion) {
    return {
      heartInterval: 2000,
      sparkleInterval: 2200,
      heartDurationMin: 8000,
      heartDurationRange: 2500,
      heartSizeMin: 10,
      heartSizeRange: 10,
      sparkleDurationMin: 1400,
      sparkleDurationRange: 900,
      cursorSparkles: false,
      cursorThrottle: 180
    };
  }

  if (isSmallMobile) {
    return {
      heartInterval: 950,
      sparkleInterval: 880,
      heartDurationMin: 9800,
      heartDurationRange: 4400,
      heartSizeMin: 10,
      heartSizeRange: 15,
      sparkleDurationMin: 1700,
      sparkleDurationRange: 1600,
      cursorSparkles: false,
      cursorThrottle: 110
    };
  }

  if (isTablet) {
    return {
      heartInterval: 700,
      sparkleInterval: 620,
      heartDurationMin: 8500,
      heartDurationRange: 4200,
      heartSizeMin: 11,
      heartSizeRange: 18,
      sparkleDurationMin: 1900,
      sparkleDurationRange: 1700,
      cursorSparkles: !isCoarsePointer,
      cursorThrottle: 85
    };
  }

  return {
    heartInterval: 520,
    sparkleInterval: 360,
    heartDurationMin: 7000,
    heartDurationRange: 5000,
    heartSizeMin: 12,
    heartSizeRange: 24,
    sparkleDurationMin: 2500,
    sparkleDurationRange: 2400,
    cursorSparkles: true,
    cursorThrottle: 65
  };
}

function updateLoveCounter() {
  const now = new Date();
  const diff = now - loveDate;
  const days = Math.max(0, Math.floor(diff / (1000 * 60 * 60 * 24)));
  daysCount.textContent = days.toLocaleString();
}

function typeWriter(text, element, speed = 30) {
  element.textContent = "";
  let i = 0;

  const intervalId = setInterval(() => {
    element.textContent += text.charAt(i);
    i += 1;

    if (i >= text.length) {
      clearInterval(intervalId);
    }
  }, speed);
}

function revealLoveMessage() {
  loveMessageSection.classList.remove("hidden");
  loveMessageSection.classList.add("in-view");

  if (sectionObserver) {
    sectionObserver.observe(loveMessageSection);
  }

  if (!typingStarted) {
    typingStarted = true;
    typeWriter(romanticMessage, typedMessage, 26);
  }

  loveMessageSection.scrollIntoView({
    behavior: "smooth",
    block: "start"
  });
}

function toggleSurprise() {
  surpriseMessage.classList.toggle("hidden");
  if (surpriseMessage.classList.contains("hidden")) {
    surpriseBtn.textContent = "Open this ";
  } else {
    surpriseBtn.textContent = "You opened it ";
  }
}

function syncMusicButtonUI() {
  musicToggle.classList.toggle("playing", isMusicPlaying);
  musicToggle.textContent = isMusicPlaying ? "" : "";
  musicToggle.title = isMusicPlaying ? "Pause music" : "Play music";
  musicToggle.setAttribute("aria-label", musicToggle.title);
}

async function toggleMusic() {
  try {
    if (isMusicPlaying) {
      bgMusic.pause();
      isMusicPlaying = false;
      syncMusicButtonUI();
      return;
    }

    await bgMusic.play();
    isMusicPlaying = true;
    syncMusicButtonUI();
  } catch (error) {
    isMusicPlaying = false;
    syncMusicButtonUI();
  }
}

function spawnHeart() {
  const profile = motionProfile || getMotionProfile();
  const heart = document.createElement("span");
  heart.className = "heart";
  heart.textContent = Math.random() > 0.35 ? "" : "";

  const left = 2 + Math.random() * 96;
  const duration = profile.heartDurationMin + Math.random() * profile.heartDurationRange;
  const size = profile.heartSizeMin + Math.random() * profile.heartSizeRange;

  heart.style.left = `${left}vw`;
  heart.style.bottom = "-40px";
  heart.style.fontSize = `${size}px`;
  heart.style.animationDuration = `${duration}ms`;

  heartContainer.appendChild(heart);

  setTimeout(() => heart.remove(), duration);
}

function spawnSparkle() {
  const profile = motionProfile || getMotionProfile();
  const sparkle = document.createElement("span");
  sparkle.className = "sparkle";

  const left = 3 + Math.random() * 94;
  const top = Math.random() * 100;
  const duration = profile.sparkleDurationMin + Math.random() * profile.sparkleDurationRange;

  sparkle.style.left = `${left}vw`;
  sparkle.style.top = `${top}vh`;
  sparkle.style.animationDuration = `${duration}ms`;

  sparkleContainer.appendChild(sparkle);

  setTimeout(() => sparkle.remove(), duration);
}

function initParticles() {
  motionProfile = getMotionProfile();
  setInterval(spawnHeart, motionProfile.heartInterval);
  setInterval(spawnSparkle, motionProfile.sparkleInterval);
}

function initScrollReveal() {
  const sections = document.querySelectorAll(".section");
  sectionObserver = new IntersectionObserver(
    (entries, observer) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add("in-view");
          observer.unobserve(entry.target);
        }
      });
    },
    {
      threshold: 0.15,
      rootMargin: "0px 0px -10% 0px"
    }
  );

  sections.forEach((section) => {
    if (!section.classList.contains("hidden")) {
      sectionObserver.observe(section);
    }
  });
}

function spawnCursorSparkle(x, y) {
  const sparkle = document.createElement("span");
  sparkle.className = "cursor-sparkle";
  sparkle.style.left = `${x}px`;
  sparkle.style.top = `${y}px`;
  sparkle.style.animationDuration = `${450 + Math.random() * 500}ms`;
  sparkleContainer.appendChild(sparkle);
  setTimeout(() => sparkle.remove(), 900);
}

function initCursorSparkles() {
  if (!motionProfile.cursorSparkles) {
    return;
  }

  let lastTime = 0;
  document.addEventListener("pointermove", (event) => {
    const now = Date.now();
    if (now - lastTime < motionProfile.cursorThrottle) {
      return;
    }

    lastTime = now;
    spawnCursorSparkle(event.clientX, event.clientY);
  });
}

function initEvents() {
  revealBtn.addEventListener("click", revealLoveMessage);
  surpriseBtn.addEventListener("click", toggleSurprise);
  musicToggle.addEventListener("click", toggleMusic);
}

function init() {
  updateLoveCounter();
  syncMusicButtonUI();
  initEvents();
  initScrollReveal();
  initParticles();
  initCursorSparkles();
}

init();

:root {
  --pink: #f9c6d3;
  --lavender: #e6d9ff;
  --soft-white: #fff8fc;
  --peach: #ffe8d6;
  --rose: #ff8fb8;
  --violet: #7f6ba8;
  --text: #5a4a68;
  --shadow: 0 12px 30px rgba(127, 107, 168, 0.15);
  --glow: 0 0 25px rgba(255, 143, 184, 0.45);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  min-height: 100vh;
  font-family: "Poppins", sans-serif;
  color: var(--text);
  background: linear-gradient(140deg, var(--soft-white), var(--lavender), var(--peach));
  overflow-x: hidden;
  position: relative;
}

.bg-glow {
  position: fixed;
  inset: -20%;
  background:
    radial-gradient(circle at 20% 20%, rgba(255, 143, 184, 0.25), transparent 32%),
    radial-gradient(circle at 80% 30%, rgba(230, 217, 255, 0.35), transparent 40%),
    radial-gradient(circle at 50% 80%, rgba(255, 232, 214, 0.4), transparent 38%);
  filter: blur(22px);
  z-index: -3;
  animation: pulseGlow 8s ease-in-out infinite alternate;
}

#heartContainer,
#sparkleContainer {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: -2;
  overflow: hidden;
}

.heart,
.sparkle {
  position: absolute;
  opacity: 0;
  will-change: transform, opacity;
}

.heart {
  color: rgba(255, 125, 169, 0.65);
  text-shadow: var(--glow);
  animation: floatUp linear forwards;
}

.sparkle {
  width: 6px;
  height: 6px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 0 16px rgba(255, 255, 255, 0.9);
  animation: twinkle linear forwards;
}

main {
  width: min(1100px, 92vw);
  margin: 0 auto;
  padding: 2rem 0 4rem;
}

.section {
  margin-top: 2rem;
  opacity: 0;
  transform: translateY(18px);
  animation: fadeInUp 0.9s ease forwards;
}

.section:nth-of-type(2) {
  animation-delay: 0.15s;
}

.section:nth-of-type(3) {
  animation-delay: 0.25s;
}

.section:nth-of-type(4) {
  animation-delay: 0.35s;
}

.section:nth-of-type(5) {
  animation-delay: 0.45s;
}

.section:nth-of-type(6) {
  animation-delay: 0.55s;
}

.card-glass {
  background: rgba(255, 255, 255, 0.56);
  border: 1px solid rgba(255, 255, 255, 0.75);
  border-radius: 30px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(8px);
  padding: clamp(1.3rem, 2.6vw, 2.2rem);
}

.hero {
  min-height: 62vh;
  display: grid;
  place-items: center;
  text-align: center;
  gap: 0.8rem;
}

.tag {
  margin: 0;
  font-size: 0.95rem;
  letter-spacing: 0.08em;
  text-transform: lowercase;
  color: #8b74af;
}

.hero-title,
.section-title {
  margin: 0;
  font-family: "Pacifico", "Dancing Script", cursive;
  color: #7d4f98;
  text-shadow: 0 4px 16px rgba(255, 143, 184, 0.3);
}

.hero-title {
  font-size: clamp(2.3rem, 8vw, 4.9rem);
  animation: textFloat 3.4s ease-in-out infinite;
}

.hero-subtitle {
  margin: 0;
  font-size: clamp(1rem, 2vw, 1.35rem);
}

.section-title {
  font-size: clamp(1.6rem, 4.8vw, 2.6rem);
  text-align: center;
}

.btn {
  border: 0;
  border-radius: 999px;
  padding: 0.85rem 1.5rem;
  font-weight: 600;
  font-size: 1rem;
  cursor: pointer;
  transition: transform 220ms ease, box-shadow 220ms ease, background 250ms ease;
}

.btn:hover {
  transform: translateY(-3px) scale(1.03);
}

.btn:active {
  transform: translateY(0) scale(0.98);
}

.btn-primary {
  background: linear-gradient(120deg, #ffafcc, #ffc8dd);
  color: #652b46;
  box-shadow: 0 10px 20px rgba(255, 175, 204, 0.35);
}

.btn-secondary {
  background: linear-gradient(120deg, #e5c7ff, #ffd6e0);
  color: #4e356b;
  box-shadow: 0 10px 20px rgba(204, 168, 238, 0.3);
}

.hidden {
  display: none;
}

.typed-message {
  margin-top: 1rem;
  min-height: 150px;
  line-height: 1.75;
  font-size: 1.04rem;
  white-space: pre-wrap;
}

.reasons-grid {
  margin-top: 1.2rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.reason-card {
  padding: 1.05rem;
  border-radius: 20px;
  background: linear-gradient(145deg, rgba(255, 255, 255, 0.76), rgba(255, 232, 244, 0.88));
  border: 1px solid rgba(255, 255, 255, 0.8);
  box-shadow: 0 10px 18px rgba(151, 121, 181, 0.15);
  transition: transform 240ms ease, box-shadow 240ms ease;
}

.reason-card:hover {
  transform: translateY(-7px) scale(1.02);
  box-shadow: 0 16px 25px rgba(151, 121, 181, 0.24);
}


.counter-value {
  font-size: clamp(1.2rem, 3.8vw, 1.8rem);
  text-align: center;
  font-weight: 700;
  color: #694e8d;
  margin: 1rem 0 0.4rem;
}

#daysCount {
  font-size: clamp(1.7rem, 5vw, 2.6rem);
  color: #ff4f98;
  text-shadow: var(--glow);
}

.counter-note {
  margin: 0;
  text-align: center;
  opacity: 0.85;
}

#surpriseSection {
  text-align: center;
}

.surprise-message {
  margin-top: 1rem;
  font-family: "Dancing Script", cursive;
  font-size: clamp(1.4rem, 4vw, 2.1rem);
  color: #d63d87;
  text-shadow: var(--glow);
  animation: popIn 500ms ease forwards;
}

.music-toggle {
  position: fixed;
  top: 14px;
  right: 14px;
  z-index: 15;
  border: 0;
  border-radius: 999px;
  padding: 0.65rem 1rem;
  font-weight: 600;
  background: rgba(255, 255, 255, 0.78);
  color: #6b4a8a;
  cursor: pointer;
  box-shadow: var(--shadow);
  transition: transform 200ms ease;
}

.music-toggle:hover {
  transform: translateY(-2px);
}

.footer {
  text-align: center;
  padding: 1.2rem 1rem 2.4rem;
  font-size: 0.95rem;
  color: #7a5f96;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(18px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes textFloat {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-6px);
  }
}

@keyframes pulseGlow {
  from {
    transform: scale(1);
  }

  to {
    transform: scale(1.08);
  }
}

@keyframes floatUp {
  0% {
    opacity: 0;
    transform: translateY(40px) scale(0.8);
  }

  10%,
  90% {
    opacity: 1;
  }

  100% {
    opacity: 0;
    transform: translateY(-120vh) scale(1.25);
  }
}

@keyframes twinkle {
  0% {
    opacity: 0;
    transform: scale(0.4);
  }

  20%,
  80% {
    opacity: 1;
    transform: scale(1);
  }

  100% {
    opacity: 0;
    transform: scale(0.2) translateY(-22vh);
  }
}

@keyframes popIn {
  from {
    opacity: 0;
    transform: scale(0.7) translateY(8px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@media (max-width: 720px) {
  main {
    width: min(680px, 94vw);
  }

  .card-glass {
    border-radius: 24px;
    padding: 1rem;
  }

  .music-toggle {
    top: 10px;
    right: 10px;
    font-size: 0.88rem;
  }
}

