  text-align: center;
}

.floating-love-note {
  margin: 0.35rem 0 0;
  font-family: "Dancing Script", cursive;
  font-size: clamp(1.2rem, 3vw, 1.9rem);
  color: #d05899;
  text-shadow: var(--soft-glow);
  animation: gentleFloat 4.6s ease-in-out infinite;
}

.cute-divider {
  text-align: center;
  margin: 1.2rem 0 0.2rem;
  color: #c074ac;
  letter-spacing: 0.22rem;
  opacity: 0.9;
  user-select: none;
}

.btn {
  position: relative;
  overflow: hidden;
  border: 0;
  border-radius: 999px;
  min-height: 48px;
  padding: 12px 20px;
  font-weight: 600;
  font-size: 1rem;
  cursor: pointer;
  touch-action: manipulation;
  transition: transform 220ms ease, box-shadow 220ms ease, filter 220ms ease;
}

.btn::after {
  content: "✨";
  position: absolute;
  top: -12px;
  left: -18px;
  opacity: 0;
  transform: rotate(-20deg);
  transition: transform 320ms ease, opacity 320ms ease;
}

.btn:hover {
  transform: translateY(-3px) scale(1.05);
  filter: saturate(1.08);
}

.btn:hover::after {
  opacity: 1;
  transform: translateX(125px) rotate(20deg);
}

.btn:active {
  animation: bounceTap 220ms ease;
}

.btn-primary {
  background: linear-gradient(120deg, #ffb6cf, #ffc6ef, #ffd8e7);
  color: #71365c;
  box-shadow: 0 10px 26px rgba(255, 138, 182, 0.38);
}

.btn-secondary {
  background: linear-gradient(120deg, #e4d4ff, #ffcde0, #ffd6cc);
  color: #5a387b;
  box-shadow: 0 10px 26px rgba(174, 131, 236, 0.3);
}

.btn-primary:hover,
.btn-secondary:hover {
  box-shadow: 0 14px 30px rgba(255, 135, 181, 0.42);
}

.hidden {
  display: none;
}

.typed-message {
  margin-top: 1rem;
  min-height: 150px;
  line-height: 1.83;
  font-size: 1.04rem;
  white-space: pre-wrap;
  overflow-wrap: anywhere;
}

.reasons-grid {
  margin-top: 1.2rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.reason-card {
  position: relative;
  padding: 1.1rem;
  border-radius: 24px;
  background: linear-gradient(145deg, rgba(255, 255, 255, 0.8), rgba(255, 228, 240, 0.9));
  border: 1px solid rgba(255, 255, 255, 0.86);
  box-shadow: 0 12px 22px rgba(151, 121, 181, 0.16);
  transition: transform 240ms ease, box-shadow 240ms ease;
}

.reason-card::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background: linear-gradient(115deg, transparent 20%, rgba(255, 255, 255, 0.45) 50%, transparent 75%);
  opacity: 0;
  transform: translateX(-35%);
  transition: transform 340ms ease, opacity 340ms ease;
}

.reason-card:hover {
  transform: translateY(-7px);
  box-shadow: 0 16px 28px rgba(151, 121, 181, 0.26);
}

.reason-card:hover::before {
  opacity: 1;
  transform: translateX(35%);
}

.reason-card:active {
  transform: translateY(-3px);
}

.counter-value {
  font-size: clamp(1.2rem, 3.8vw, 1.8rem);
  text-align: center;
  font-weight: 700;
  color: #694e8d;
  margin: 1rem 0 0.4rem;
}

#daysCount {
  font-size: clamp(1.7rem, 5vw, 2.6rem);
  color: #ff4f98;
  text-shadow: var(--soft-glow);
}

.counter-note {
  margin: 0;
  text-align: center;
  opacity: 0.85;
}

#surpriseSection {
  text-align: center;
}

.surprise-message {
  margin-top: 1rem;
  font-family: "Dancing Script", cursive;
  font-size: clamp(1.5rem, 4vw, 2.2rem);
  color: #d63d87;
  text-shadow: var(--soft-glow);
  animation: popIn 500ms ease forwards;
}

.music-toggle {
  position: fixed;
  top: 14px;
  right: 14px;
  z-index: 15;
  width: 58px;
  height: 58px;
  border: 0;
  border-radius: 999px;
  font-size: 1.2rem;
  display: grid;
  place-items: center;
  background: radial-gradient(circle at 30% 30%, #ffd5e8, #e9d7ff);
  color: #6c4a93;
  cursor: pointer;
  box-shadow: var(--shadow);
  transition: transform 200ms ease, box-shadow 200ms ease;
}

.music-toggle:hover {
  transform: translateY(-2px) scale(1.04);
  box-shadow: 0 16px 28px rgba(117, 94, 152, 0.28);
}

.music-toggle.playing {
  animation: heartbeat 1.2s ease-in-out infinite;
}

.footer {
  text-align: center;
  padding: 1.2rem 1rem 2.4rem;
  font-size: 0.95rem;
  color: #7a5f96;
}

.heartbeat {
  animation: heartbeat 1.45s ease-in-out infinite;
}

.heartbeat-soft {
  display: inline-block;
  animation: heartbeat 1.95s ease-in-out infinite;
}

@keyframes textFloat {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-8px);
  }
}

@keyframes gentleFloat {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-6px);
  }
}

@keyframes pulseGlow {
  from {
    transform: scale(1);
  }

  to {
    transform: scale(1.07);
  }
}

@keyframes heartbeat {
  0%,
  100% {
    transform: scale(1);
  }

  35% {
    transform: scale(1.08);
  }

  52% {
    transform: scale(1.03);
  }
}

@keyframes bounceTap {
  0% {
    transform: scale(1);
  }

  45% {
    transform: scale(0.93);
  }

  100% {
    transform: scale(1.02);
  }
}

@keyframes floatUp {
  0% {
    opacity: 0;
    transform: translateY(40px) scale(0.8);
  }

  10%,
  90% {
    opacity: 1;
  }

  100% {
    opacity: 0;
    transform: translateY(-120vh) scale(1.3);
  }
}

@keyframes twinkle {
  0% {
    opacity: 0;
    transform: scale(0.4);
  }

  20%,
  80% {
    opacity: 1;
    transform: scale(1);
  }

  100% {
    opacity: 0;
    transform: scale(0.2) translateY(-20vh);
  }
}

@keyframes popIn {
  from {
    opacity: 0;
    transform: scale(0.75) translateY(8px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@media (max-width: 768px) {
  main {
    width: 94vw;
    padding: 1.5rem 0 3.2rem;
  }

  .section {
    margin-top: 1.6rem;
  }

  .card-glass {
    border-radius: 28px;
    padding: 1.1rem;
  }

  .hero {
    min-height: 56vh;
  }

  .hero-title {
    font-size: clamp(2.4rem, 11vw, 4.2rem);
  }

  .section-title {
    font-size: clamp(1.8rem, 7.2vw, 2.5rem);
  }

  .hero-subtitle,
  .typed-message,
  .counter-note {
    font-size: clamp(0.98rem, 2.8vw, 1.06rem);
  }

  .reasons-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 0.85rem;
  }

  .cute-divider {
    letter-spacing: 0.16rem;
    margin: 0.95rem 0 0.1rem;
  }

  .btn {
    width: 100%;
    max-width: 360px;
  }

  .music-toggle {
    width: 52px;
    height: 52px;
    top: 10px;
    right: 10px;
    font-size: 1.08rem;
  }
}

@media (max-width: 480px) {
  main {
    width: 95vw;
    padding: 1rem 0 2.6rem;
  }

  .section {
    margin-top: 1.2rem;
  }

  .card-glass {
    border-radius: 22px;
    padding: 0.95rem;
  }

  .hero {
    min-height: 52vh;
    gap: 0.55rem;
  }

  .tag {
    font-size: 0.78rem;
    letter-spacing: 0.05em;
  }

  .hero-title {
    font-size: clamp(2.15rem, 13vw, 3.1rem);
  }

  .section-title {
    font-size: clamp(1.7rem, 9vw, 2.2rem);
  }

  .floating-love-note {
    font-size: clamp(1.05rem, 5vw, 1.4rem);
  }

  .typed-message {
    min-height: 120px;
    line-height: 1.7;
  }

  .reasons-grid {
    grid-template-columns: 1fr;
    gap: 0.72rem;
  }

  .reason-card {
    border-radius: 18px;
    padding: 0.95rem;
  }

  .btn {
    width: 100%;
    max-width: none;
    font-size: 0.98rem;
    margin-top: 0.3rem;
  }

  .music-toggle {
    width: 48px;
    height: 48px;
    top: 8px;
    right: 8px;
    font-size: 1rem;
  }

  .heart,
  .sparkle,
  .cursor-sparkle {
    transform: scale(0.8);
  }

  .footer {
    font-size: 0.86rem;
    padding: 1rem 0.8rem 2rem;
  }

  .bg-glow {
    filter: blur(16px);
  }
}

@media (hover: none) {
  .btn:hover,
  .reason-card:hover {
    transform: none;
    filter: none;
  }

  .btn:active {
    transform: scale(0.98);
  }

  .reason-card:active {
    transform: translateY(-2px);
  }

  .btn::after {
    display: none;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
